// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.OptimizationGoal;
import org.junit.jupiter.api.Test;

class PackedJoinSubsetKernelTest {

	@Test
	void selectsDenseSparseAndMultiwordSubsetKernelsAtExactBoundaries() {
		assertEquals(PackedJoinEnumerator.DENSE_SUBSETS,
				PackedJoinEnumerator.subsetKernelForFactorCount(16));
		assertEquals(PackedJoinEnumerator.SPARSE_LONG_SUBSETS,
				PackedJoinEnumerator.subsetKernelForFactorCount(17));
		assertEquals(PackedJoinEnumerator.SPARSE_LONG_SUBSETS,
				PackedJoinEnumerator.subsetKernelForFactorCount(64));
		assertEquals(PackedJoinEnumerator.INTERNED_MULTIWORD_SUBSETS,
				PackedJoinEnumerator.subsetKernelForFactorCount(65));
	}

	@Test
	void sparseLongKernelPlansASeventeenFactorConnectedRegion() {
		TupleExpr selected = PackedCascadesPlanner.optimize(chain(17), OptimizationGoal.root()).selectedPlan();

		assertEquals(17, factorCount(selected));
		Join first = firstJoin(selected);
		String left = ((StatementPattern) first.getLeftArg()).getPredicateVar().getValue().stringValue();
		String right = ((StatementPattern) first.getRightArg()).getPredicateVar().getValue().stringValue();
		assertTrue(left.equals("urn:factor:15") && right.equals("urn:factor:16")
				|| left.equals("urn:factor:16") && right.equals("urn:factor:15"));
	}

	@Test
	void multiwordKernelPlansEveryFactorWithoutBooleanSelectionState() {
		TupleExpr selected = PackedCascadesPlanner.optimize(chain(65), OptimizationGoal.root()).selectedPlan();

		assertEquals(65, factorCount(selected));
		assertEquals("urn:factor:64", leftmostFactor(selected).getPredicateVar().getValue().stringValue());
	}

	private static TupleExpr chain(int factorCount) {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		TupleExpr result = factor(values, 0, factorCount);
		for (int ordinal = 1; ordinal < factorCount; ordinal++) {
			result = new Join(result, factor(values, ordinal, factorCount));
		}
		return result;
	}

	private static StatementPattern factor(SimpleValueFactory values, int ordinal, int factorCount) {
		StatementPattern factor = new StatementPattern(Var.of("v" + ordinal),
				Var.of("predicate" + ordinal, values.createIRI("urn:factor:" + ordinal)),
				Var.of("v" + (ordinal + 1)));
		factor.setResultSizeEstimate((factorCount - ordinal) * 10.0d);
		return factor;
	}

	private static int factorCount(TupleExpr expression) {
		if (expression instanceof StatementPattern) {
			return 1;
		}
		Join join = (Join) expression;
		return factorCount(join.getLeftArg()) + factorCount(join.getRightArg());
	}

	private static StatementPattern leftmostFactor(TupleExpr expression) {
		TupleExpr current = expression;
		while (current instanceof Join join) {
			current = join.getLeftArg();
		}
		return (StatementPattern) current;
	}

	private static Join firstJoin(TupleExpr expression) {
		Join current = (Join) expression;
		while (current.getLeftArg()instanceof Join left) {
			current = left;
		}
		return current;
	}
}
